import numpy as np

def hungarian_algorithm(cost_matrix):
    original_matrix = np.array(cost_matrix, dtype=float)
    num_rows, num_cols = original_matrix.shape

    # Pad matrix if it's not square
    N = max(num_rows, num_cols)
    matrix = np.full((N, N), np.inf)
    matrix[:num_rows, :num_cols] = original_matrix

    # Step 1: Reduce matrix (subtract row/column minimums)
    for r in range(N):
        if np.any(np.isfinite(matrix[r, :])):
            matrix[r, :] -= np.min(matrix[r, :])
    for c in range(N):
        if np.any(np.isfinite(matrix[:, c])):
            matrix[:, c] -= np.min(matrix[:, c])

    star_in_row = -np.ones(N, dtype=int)
    prime_in_row = -np.ones(N, dtype=int)

    covered_rows = np.zeros(N, dtype=bool)
    covered_cols = np.zeros(N, dtype=bool)

    def find_uncovered_zero():
        for r_idx in range(N):
            if not covered_rows[r_idx]:
                for c_idx in range(N):
                    if not covered_cols[c_idx] and matrix[r_idx, c_idx] == 0 and np.isfinite(matrix[r_idx, c_idx]):
                        return r_idx, c_idx
        return -1, -1

    def find_star_in_col(c_idx):
        for r_idx in range(N):
            if star_in_row[r_idx] == c_idx:
                return r_idx
        return -1

    for r in range(N):
        for c in range(N):
            if matrix[r, c] == 0 and not covered_rows[r] and not covered_cols[c]:
                star_in_row[r] = c
                covered_rows[r] = True
                covered_cols[c] = True
                break

    covered_rows[:] = False
    covered_cols[:] = False

    step = 2

    while True:
        if step == 2:
            num_starred_zeros = 0
            for r in range(N):
                if star_in_row[r] != -1:
                    covered_cols[star_in_row[r]] = True
                    num_starred_zeros += 1

            if num_starred_zeros == N:
                step = 6
            else:
                step = 3

        elif step == 3:
            r_prime, c_prime = find_uncovered_zero()

            if r_prime == -1:
                step = 5
            else:
                prime_in_row[r_prime] = c_prime
                r_star_in_row = star_in_row[r_prime]

                if r_star_in_row == -1:
                    step = 4
                else:
                    covered_rows[r_prime] = True
                    covered_cols[r_star_in_row] = False

        elif step == 4:
            path = []
            path.append((r_prime, c_prime))

            while True:
                r_star_in_col = find_star_in_col(path[-1][1])

                if r_star_in_col != -1:
                    path.append((r_star_in_col, path[-1][1]))
                    path.append((r_star_in_col, prime_in_row[r_star_in_col]))
                else:
                    break

            for i in range(0, len(path), 2):
                star_in_row[path[i][0]] = path[i][1]

            prime_in_row[:] = -1
            covered_rows[:] = False
            covered_cols[:] = False
            step = 2

        elif step == 5:
            min_val = np.inf
            for r in range(N):
                if not covered_rows[r]:
                    for c in range(N):
                        if not covered_cols[c]:
                            min_val = min(min_val, matrix[r, c])

            if min_val == np.inf:
                break 

            for r in range(N):
                if not covered_rows[r]:
                    matrix[r, :] -= min_val
            for c in range(N):
                if covered_cols[c]:
                    matrix[:, c] += min_val

            step = 3

        elif step == 6:
            break

    assignment = []
    for r in range(num_rows):
        c = star_in_row[r]
        if c != -1 and c < num_cols:
            assignment.append((r, c))

    return assignment, matrix
